INSERT INTO `t_options` (`foreign_id`, `key`, `tab_id`, `value`, `label`, `type`, `description`, `order`, `is_visible`, `style`) VALUES
(1, 'mail_edit_token_ARRAY_message', 3, '{client_family_name} {client_first_name}様\r\n\r\n\r\nお世話になっております。\r\nワンエイトアソシエーションで御座います。\r\n\r\n\r\nQNT還元用コードの発行処理が完了しましたので受領書をお送り致します。\r\n下記にてQNT還元用コードをご確認ください。\r\n\r\n*******************\r\nこの受領書はQNTをご自身のウォレットに還元する際に必要になります。\r\n万一、ご自身の管理不足により、第三者の不正使用、紛失、漏洩、失念、盗難\r\nなどについては原因を問わず弊社並びに関連各社は一切の責任を負いません。\r\n*******************\r\n\r\n===================\r\n受領書\r\n-------------------\r\nTicket ID: {order_number}\r\n\r\n\r\n交換完了日時: {create_at}\r\n\r\n\r\n受信したBitcoinの総額: {btc_amount} BTC\r\n\r\n適用されたUSD/BTCレート: {btc_usd_rate} USD/BTC\r\n\r\n適用されたUSD/QNTレート: {qnt_usd_rate} USD/QNT\r\n\r\n交換されたQNTの総額: {token_quantity} QNT\r\n\r\n\r\nQNT還元用コード: {token_code}\r\n\r\n===================\r\n\r\n{mail_signature}', NULL, 'text', 'Edit token code message', 28, 1, NULL),
(1, 'mail_edit_token_ARRAY_subject', 3, '[Quanta]ワンエイトアソシエーション株式会社　受領書をお送りいたします', NULL, 'string', 'Edit token code subject', 27, 1, NULL);